
create table if not exists public.analysis_runs (
  id uuid primary key default gen_random_uuid(),
  project_id uuid not null references public.projects(id) on delete cascade,
  run_name text not null,
  run_type text not null,
  parameters jsonb not null default '{}'::jsonb,
  status text not null default 'completed',
  records_processed bigint not null default 0,
  events_detected integer not null default 0,
  notes text,
  created_by uuid references auth.users(id) default auth.uid(),
  created_at timestamptz not null default now()
);

create table if not exists public.research_market_data (
  id bigint generated always as identity primary key,
  project_id uuid not null references public.projects(id) on delete cascade,
  symbol text not null,
  trade_date date not null,
  open_price numeric,
  high_price numeric,
  low_price numeric,
  close_price numeric,
  volume numeric,
  turnover numeric,
  transactions numeric,
  previous_close numeric,
  stock_return numeric,
  market_return numeric,
  abnormal_return numeric,
  source_name text not null default 'nepse_research_dataset',
  imported_at timestamptz not null default now(),
  unique(project_id, symbol, trade_date, source_name)
);

create index if not exists research_market_data_symbol_date_idx
on public.research_market_data(project_id, symbol, trade_date desc);
create index if not exists research_market_data_abnormal_idx
on public.research_market_data(project_id, abnormal_return);

create table if not exists public.research_events (
  id bigint generated always as identity primary key,
  project_id uuid not null references public.projects(id) on delete cascade,
  symbol text not null,
  event_date date not null,
  open_price numeric,
  high_price numeric,
  low_price numeric,
  close_price numeric,
  volume numeric,
  turnover numeric,
  transactions numeric,
  previous_close numeric,
  stock_return numeric,
  market_return numeric,
  abnormal_return numeric,
  rolling_volume_mean numeric,
  rolling_return_std numeric,
  volume_multiple numeric,
  return_sigma numeric,
  severity_score numeric,
  event_year integer,
  classification text not null default 'Unreviewed',
  review_status text not null default 'pending',
  announcement_match text,
  insider_score numeric,
  pump_score numeric,
  reviewer_notes text,
  reviewed_by uuid references auth.users(id),
  reviewed_at timestamptz,
  unique(project_id, symbol, event_date)
);

create index if not exists research_events_date_idx on public.research_events(project_id, event_date desc);
create index if not exists research_events_symbol_idx on public.research_events(project_id, symbol);
create index if not exists research_events_severity_idx on public.research_events(project_id, severity_score desc);

create table if not exists public.data_quality_issues (
  id uuid primary key default gen_random_uuid(),
  project_id uuid not null references public.projects(id) on delete cascade,
  issue_type text not null,
  symbol text,
  issue_date date,
  severity text not null default 'medium',
  title text not null,
  description text not null,
  possible_cause text,
  resolution text,
  status text not null default 'open',
  assigned_to uuid references auth.users(id),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.investigation_notes (
  id uuid primary key default gen_random_uuid(),
  project_id uuid not null references public.projects(id) on delete cascade,
  event_id bigint references public.research_events(id) on delete cascade,
  symbol text,
  note_type text not null default 'general',
  title text not null,
  body text not null,
  created_by uuid references auth.users(id) default auth.uid(),
  created_at timestamptz not null default now()
);

alter table public.analysis_runs enable row level security;
alter table public.research_market_data enable row level security;
alter table public.research_events enable row level security;
alter table public.data_quality_issues enable row level security;
alter table public.investigation_notes enable row level security;

drop policy if exists "members manage analysis runs" on public.analysis_runs;
create policy "members manage analysis runs" on public.analysis_runs for all
using (public.is_project_member(project_id))
with check (public.is_project_member(project_id));

drop policy if exists "members read market data" on public.research_market_data;
create policy "members read market data" on public.research_market_data for select
using (public.is_project_member(project_id));

drop policy if exists "members manage events" on public.research_events;
create policy "members manage events" on public.research_events for all
using (public.is_project_member(project_id))
with check (public.is_project_member(project_id));

drop policy if exists "members manage data quality" on public.data_quality_issues;
create policy "members manage data quality" on public.data_quality_issues for all
using (public.is_project_member(project_id))
with check (public.is_project_member(project_id));

drop policy if exists "members manage investigation notes" on public.investigation_notes;
create policy "members manage investigation notes" on public.investigation_notes for all
using (public.is_project_member(project_id))
with check (public.is_project_member(project_id));

do $$
declare pid uuid;
begin
  select id into pid from public.projects order by created_at desc limit 1;
  insert into public.analysis_runs
    (project_id, run_name, run_type, parameters, status, records_processed, events_detected, notes)
  select pid, 'Current 30-day / 3-sigma / 5x-volume screen',
    'abnormal_event_detection',
    '{"volatility_window":30,"return_threshold_sigma":3,"volume_window":30,"volume_multiple":5,"event_window":[-10,10]}'::jsonb,
    'completed', 530674, 845,
    'Seeded from the current abnormal-event CSV. The preliminary note reports 843 events, so this run remains subject to reconciliation.'
  where not exists (
    select 1 from public.analysis_runs
    where project_id = pid and run_name = 'Current 30-day / 3-sigma / 5x-volume screen'
  );

  insert into public.data_quality_issues
    (project_id, issue_type, severity, title, description, possible_cause, status)
  select pid, 'count_mismatch', 'high',
    '843 versus 845 event-count discrepancy',
    'The preliminary note reports 843 events, while the current abnormal-event CSV contains 845 rows.',
    'Different script versions, duplicate removal, event-window exclusions, or later data refresh.', 'open'
  where not exists (
    select 1 from public.data_quality_issues
    where project_id = pid and title = '843 versus 845 event-count discrepancy'
  );

  insert into public.data_quality_issues
    (project_id, issue_type, symbol, issue_date, severity, title, description, possible_cause, status)
  select pid, 'extreme_return', 'CORBL', '2022-01-01', 'high',
    'Extreme CORBL abnormal return around 2022',
    'The current CORBL chart contains an abnormal return near -0.69. The exact date should be identified and validated.',
    'Corporate action, unadjusted price discontinuity, symbol issue, or source-data error.', 'open'
  where not exists (
    select 1 from public.data_quality_issues
    where project_id = pid and title = 'Extreme CORBL abnormal return around 2022'
  );
end $$;

