-- V7 complete-system modules
create table if not exists public.nepse_sync_runs (
  id uuid primary key default gen_random_uuid(), sync_type text not null, status text not null default 'running',
  records_saved integer not null default 0, error_message text, started_at timestamptz not null default now(), completed_at timestamptz
);
create table if not exists public.nepse_disclosures (
  id uuid primary key default gen_random_uuid(), disclosure_key text not null unique, symbol text, title text,
  published_at timestamptz, category text, raw_data jsonb, fetched_at timestamptz not null default now()
);
alter table public.nepse_sync_runs enable row level security;
alter table public.nepse_disclosures enable row level security;
drop policy if exists "members read sync runs v7" on public.nepse_sync_runs;
create policy "members read sync runs v7" on public.nepse_sync_runs for select to authenticated using(exists(select 1 from public.project_members where user_id=auth.uid()));
drop policy if exists "members read disclosures v7" on public.nepse_disclosures;
create policy "members read disclosures v7" on public.nepse_disclosures for select to authenticated using(exists(select 1 from public.project_members where user_id=auth.uid()));
create table if not exists public.analysis_jobs (
  id uuid primary key default gen_random_uuid(), project_id uuid not null references public.projects(id) on delete cascade,
  job_type text not null check (job_type in ('event_detection','pump_detection')), status text not null default 'queued',
  parameters jsonb not null default '{}'::jsonb, result_summary jsonb, error_message text,
  requested_by uuid references auth.users(id) default auth.uid(), created_at timestamptz not null default now(),
  started_at timestamptz, completed_at timestamptz
);
create table if not exists public.pump_cycles (
  id uuid primary key default gen_random_uuid(), project_id uuid not null references public.projects(id) on delete cascade,
  analysis_run_id uuid references public.analysis_runs(id) on delete set null, symbol text not null,
  start_date date not null, peak_date date not null, end_date date not null,
  start_price numeric, peak_price numeric, end_price numeric, run_up_return numeric, reversal_return numeric,
  peak_volume_multiple numeric, cycle_days integer, pump_score numeric, status text not null default 'candidate',
  reviewer_notes text, created_at timestamptz not null default now(), unique(project_id,symbol,start_date,peak_date,end_date)
);
create table if not exists public.event_announcement_matches (
  id uuid primary key default gen_random_uuid(), project_id uuid not null references public.projects(id) on delete cascade,
  event_id bigint not null references public.research_events(id) on delete cascade,
  disclosure_id uuid not null references public.nepse_disclosures(id) on delete cascade,
  day_difference integer not null, match_status text not null default 'automatic', created_at timestamptz not null default now(),
  unique(event_id,disclosure_id)
);
alter table public.analysis_jobs enable row level security;alter table public.pump_cycles enable row level security;alter table public.event_announcement_matches enable row level security;
drop policy if exists "members manage analysis jobs" on public.analysis_jobs;create policy "members manage analysis jobs" on public.analysis_jobs for all using(public.is_project_member(project_id)) with check(public.is_project_member(project_id));
drop policy if exists "members manage pump cycles" on public.pump_cycles;create policy "members manage pump cycles" on public.pump_cycles for all using(public.is_project_member(project_id)) with check(public.is_project_member(project_id));
drop policy if exists "members manage event matches" on public.event_announcement_matches;create policy "members manage event matches" on public.event_announcement_matches for all using(public.is_project_member(project_id)) with check(public.is_project_member(project_id));

create or replace function public.recalculate_event_scores(p_project_id uuid,p_severity_weight numeric,p_volume_weight numeric,p_sigma_weight numeric,p_unexplained_weight numeric)
returns integer language plpgsql security definer set search_path=public as $$
declare n integer;
begin
 update public.research_events set
  insider_score=least(100,greatest(0,
    coalesce(severity_score,0)/100*p_severity_weight+
    least(coalesce(volume_multiple,0)/15,1)*p_volume_weight+
    least(coalesce(return_sigma,0)/6,1)*p_sigma_weight+
    case when coalesce(announcement_match,'') in ('','Unmatched','None') then p_unexplained_weight else 0 end)),
  pump_score=least(100,greatest(0,
    case when coalesce(abnormal_return,0)>0 then least(abnormal_return/0.10,1)*35 else 0 end+
    least(coalesce(volume_multiple,0)/15,1)*35+
    coalesce(severity_score,0)/100*30))
 where project_id=p_project_id;
 get diagnostics n=row_count;return n;
end $$;

create or replace function public.match_event_announcements(p_project_id uuid,p_window_days integer default 10)
returns integer language plpgsql security definer set search_path=public as $$
declare n integer;
begin
 insert into public.event_announcement_matches(project_id,event_id,disclosure_id,day_difference)
 select p_project_id,e.id,d.id,(d.published_at::date-e.event_date)
 from public.research_events e join public.nepse_disclosures d on upper(coalesce(d.symbol,''))=upper(e.symbol)
 where e.project_id=p_project_id and d.published_at is not null and abs(d.published_at::date-e.event_date)<=p_window_days
 on conflict(event_id,disclosure_id) do update set day_difference=excluded.day_difference;
 get diagnostics n=row_count;
 update public.research_events e set announcement_match=case
  when exists(select 1 from public.event_announcement_matches m where m.event_id=e.id and m.day_difference<0) then 'Public disclosure before event'
  when exists(select 1 from public.event_announcement_matches m where m.event_id=e.id and m.day_difference=0) then 'Disclosure on event day'
  when exists(select 1 from public.event_announcement_matches m where m.event_id=e.id and m.day_difference>0) then 'Disclosure after event'
  else 'Unmatched' end where e.project_id=p_project_id;
 return n;
end $$;

do $$ declare pid uuid; begin select id into pid from public.projects order by created_at desc limit 1; perform public.recalculate_event_scores(pid,35,25,25,15); end $$;
